import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Product",
  subtitle: "Enterprise cybersecurity platform with AI-powered threat detection, zero-trust architecture, and comprehensive protection for modern cloud infrastructure.",
  sections: [
    {
      title: "Core Security Modules",
      description: "Our platform provides comprehensive protection across all layers of your infrastructure.",
      gridClass: "info-grid-3",
      grid: [
        {
          icon: "M13 10V3L4 14h7v7l9-11h-7z",
          title: "AI Threat Detection",
          description: "Machine learning-powered anomaly detection using Isolation Forest algorithms for real-time behavioral analysis and predictive threat modeling.",
          cta: { text: "Learn more", link: "/features/threat-detection" }
        },
        {
          icon: "M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z",
          title: "Zero-Trust Architecture",
          description: "Never trust, always verify. Comprehensive ZTA with micro-segmentation, JIT access, and continuous behavioral biometric verification.",
          cta: { text: "Learn more", link: "/features/zero-trust" }
        },
        {
          icon: "M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10",
          title: "Blockchain Audit Trail",
          description: "Immutable, cryptographically verified audit logs using blockchain technology for tamper-proof compliance reporting.",
          cta: { text: "Learn more", link: "/features/blockchain-audit" }
        },
        {
          icon: "M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4",
          title: "Quantum-Resistant Crypto",
          description: "Post-quantum cryptographic algorithms (ML-KEM, SLH-DSA) with hybrid classical + quantum-resistant encryption.",
          cta: { text: "Learn more", link: "/features/quantum-crypto" }
        },
        {
          icon: "M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z",
          title: "SOAR & Playbooks",
          description: "Security orchestration, automation, and response with customizable playbooks and 500+ tool integrations.",
          cta: { text: "Learn more", link: "/features/soar" }
        },
        {
          icon: "M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z",
          title: "Compliance Monitoring",
          description: "Real-time compliance scanning for SOC 2, ISO 27001, GDPR, HIPAA, PCI-DSS with automated reporting.",
          cta: { text: "Learn more", link: "/features/compliance" }
        }
      ]
    },
    {
      title: "Platform Capabilities",
      description: "Additional security features to protect every aspect of your digital infrastructure.",
      grid: true,
      gridClass: "info-grid-3",
      grid: [
        {
          icon: "M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z",
          title: "Privacy-Preserving ML",
          description: "Federated learning and differential privacy for secure AI analytics without compromising data privacy."
        },
        {
          icon: "M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0zM7 17a2 2 0 100-4 2 2 0 000 4z",
          title: "Web3 Identity",
          description: "Decentralized identity (DID) and wallet-based authentication with verifiable credentials."
        },
        {
          icon: "M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z",
          title: "RASP Protection",
          description: "Runtime Application Self-Protection with in-app threat detection and automatic attack neutralization."
        },
        {
          icon: "M15 12a3 3 0 11-6 0 3 3 0 016 0z M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z",
          title: "Deceptive Security",
          description: "Advanced honeypots, honeytokens, and deception technology for early intruder detection."
        },
        {
          icon: "M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4",
          title: "Confidential Computing",
          description: "Hardware-secured enclaves (SGX, SEV) for protected data processing with data encryption during use."
        },
        {
          icon: "M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01",
          title: "SBOM Management",
          description: "Software Bill of Materials for complete supply chain visibility, vulnerability tracking, and license compliance."
        }
      ]
    },
    {
      stats: [
        { value: "99.9%", label: "Detection Accuracy" },
        { value: "<100ms", label: "Response Time" },
        { value: "500+", label: "Security Checks" },
        { value: "24/7", label: "Active Monitoring" }
      ]
    }
  ],
  color: "#4f46e5"
};

function Product() {
  return <InfoPageLayout {...pageData} />;
}

export default Product;
